CREATE TABLE profiles (
  code CHAR(5),
  name VARCHAR(100) NOT NULL,
  bio TEXT
);

CREATE TABLE events (
  id SERIAL PRIMARY KEY,
  event_date DATE,
  start_time TIME,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  duration INTERVAL DEFAULT '1 hour'
);

SELECT NOW() + INTERVAL '30 days';
SELECT age(CURRENT_DATE, '1990-01-15');

CREATE TABLE configs (
  id SERIAL PRIMARY KEY,
  data JSONB NOT NULL DEFAULT '{}'
);

INSERT INTO configs (data) VALUES ('{"theme": "dark", "lang": "id"}');

-- Query JSONB
SELECT data->>'theme' FROM configs;
SELECT * FROM configs WHERE data @> '{"lang": "id"}';
SELECT * FROM configs WHERE data ? 'theme';

-- GIN Index untuk JSONB
CREATE INDEX idx_configs_data ON configs USING GIN (data);

CREATE TABLE articles (
  id SERIAL PRIMARY KEY,
  title TEXT,
  tags TEXT[] DEFAULT '{}'
);

INSERT INTO articles (title, tags) VALUES ('Intro PG', ARRAY['postgresql','tutorial']);
SELECT * FROM articles WHERE 'tutorial' = ANY(tags);
SELECT * FROM articles WHERE tags @> ARRAY['postgresql'];
SELECT unnest(tags) FROM articles;

CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE TABLE sessions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id INT REFERENCES users(id),
  token TEXT UNIQUE NOT NULL
);

CREATE TYPE status AS ENUM ('active', 'inactive', 'banned');

CREATE TABLE accounts (
  id SERIAL PRIMARY KEY,
  is_active BOOLEAN DEFAULT true,
  status status DEFAULT 'active',
  ip_address INET,
  avatar BYTEA
);
